css:
:root{--ink:#0F1526;--cream:#F5F0E8;--gold:#C9A84C;--gold-lt:#E8C96A;--slate:#2B2E3B;--slate-mid:#4A4E60;--slate-light:#8B8FA8;--green:#3D7A5F;--rule:rgba(43,46,59,0.12);--rule-gold:rgba(201,168,76,0.25);--fd:'Cormorant Garamond',Georgia,serif;--fs:'Syne',sans-serif;--fm:'DM Mono',monospace}
*{margin:0;padding:0;box-sizing:border-box}body{background:var(--cream);color:var(--slate);font-family:var(--fs);line-height:1.6}
.cover{background:var(--ink);color:var(--cream);padding:3rem;position:relative;overflow:hidden}
.cover::before{content:'';position:absolute;top:-30%;right:-10%;width:500px;height:500px;background:radial-gradient(circle,rgba(201,168,76,0.08) 0%,transparent 65%);pointer-events:none}
.cey{font-family:var(--fm);font-size:.58rem;letter-spacing:.2em;text-transform:uppercase;color:var(--gold);margin-bottom:1.25rem;display:flex;align-items:center;gap:.75rem}
.cey::before{content:'';width:24px;height:1px;background:var(--gold);flex-shrink:0}
.cover h1{font-family:var(--fd);font-size:clamp(2.2rem,4.5vw,4rem);font-weight:300;line-height:.95;letter-spacing:-.02em;color:var(--cream);margin-bottom:1rem}
.cover h1 em{font-style:italic;color:var(--gold-lt)}
.csub{font-family:var(--fs);font-size:.8rem;color:rgba(245,240,232,.55);max-width:540px;line-height:1.65;margin-bottom:1.5rem}
.cmeta{font-family:var(--fm);font-size:.6rem;color:rgba(245,240,232,.35);letter-spacing:.08em;padding-top:1.5rem;border-top:1px solid rgba(245,240,232,.1)}
.sec{border-bottom:1px solid var(--rule);padding:2.5rem 3rem}.sec:last-child{border-bottom:none}
.sey{font-family:var(--fm);font-size:.56rem;letter-spacing:.18em;text-transform:uppercase;color:var(--gold);margin-bottom:.6rem}
h2{font-family:var(--fd);font-size:1.9rem;font-weight:300;color:var(--ink);margin-bottom:.75rem;line-height:1.05}
h3{font-family:var(--fs);font-size:.92rem;font-weight:700;color:var(--slate);margin:1.25rem 0 .45rem}
h4{font-family:var(--fm);font-size:.62rem;letter-spacing:.12em;text-transform:uppercase;color:var(--slate-light);margin:.9rem 0 .35rem}
p{font-family:var(--fs);font-size:.8rem;color:var(--slate-mid);line-height:1.75;margin-bottom:.7rem}p strong{color:var(--slate)}
.qb{background:var(--ink);padding:1.75rem 2rem;margin:1.25rem 0}
.qb .ql{font-family:var(--fm);font-size:.52rem;letter-spacing:.15em;text-transform:uppercase;color:rgba(201,168,76,.65);margin-bottom:.6rem}
.qb p{font-family:var(--fd);font-size:1.35rem;font-weight:300;line-height:1.15;color:var(--cream);margin-bottom:.4rem}
.qb p em{color:var(--gold-lt)}.qb .qs{font-family:var(--fs);font-size:.78rem;color:rgba(245,240,232,.6);line-height:1.7;margin-bottom:0}
.pb{display:grid;grid-template-columns:1fr auto;align-items:center;background:var(--ink);padding:.9rem 1.4rem;margin:1.25rem 0 0}
.pl{font-family:var(--fm);font-size:.58rem;letter-spacing:.14em;text-transform:uppercase;color:var(--gold)}
.pp{font-family:var(--fd);font-size:1.25rem;font-weight:300;color:var(--cream)}
.pbd{background:rgba(15,21,38,.04);padding:1.4rem;border-left:2px solid var(--rule-gold);margin-bottom:1rem}.pbd p{font-size:.79rem}
.sb{display:grid;grid-template-columns:repeat(4,1fr);background:var(--ink);border:1px solid rgba(245,240,232,.07);margin:1.25rem 0}
.sc{padding:1.1rem 1.4rem;border-right:1px solid rgba(245,240,232,.07);text-align:center}.sc:last-child{border-right:none}
.sv{font-family:var(--fd);font-size:1.7rem;font-weight:300;color:var(--gold-lt);line-height:1}
.sl{font-family:var(--fm);font-size:.5rem;letter-spacing:.1em;text-transform:uppercase;color:rgba(245,240,232,.3);margin-top:.25rem}
table{width:100%;border-collapse:collapse;margin:1rem 0;font-size:.76rem}
th{font-family:var(--fm);font-size:.52rem;letter-spacing:.1em;text-transform:uppercase;color:var(--slate-light);padding:.6rem .9rem;border-bottom:1px solid var(--rule);background:rgba(245,240,232,.65);text-align:left}
td{padding:.75rem .9rem;border-bottom:1px solid var(--rule);color:var(--slate-mid);line-height:1.5;vertical-align:top}
tr:last-child td{border-bottom:none}td:first-child{color:var(--slate);font-weight:600}
tr:nth-child(even) td{background:rgba(245,240,232,.4)}
ul.bul{list-style:none;padding:0;margin:.5rem 0}
ul.bul li{font-family:var(--fs);font-size:.79rem;color:var(--slate-mid);padding:.38rem 0;border-bottom:1px solid var(--rule);display:grid;grid-template-columns:14px 1fr;gap:.5rem;line-height:1.55}
ul.bul li:last-child{border-bottom:none}ul.bul li::before{content:'—';font-family:var(--fm);color:var(--gold);font-size:.58rem;padding-top:.05rem}
.seo{background:rgba(15,21,38,.04);padding:1.4rem;border-left:3px solid var(--gold);margin:1rem 0}.seo p{font-size:.76rem;margin-bottom:.35rem}.seo strong{color:var(--ink)}
.obj{background:rgba(61,122,95,.07);border-left:3px solid var(--green);padding:.9rem 1.1rem;margin:.9rem 0}.objl{font-family:var(--fm);font-size:.5rem;letter-spacing:.1em;text-transform:uppercase;color:var(--green);margin-bottom:.3rem}.obj p{font-size:.77rem;color:var(--slate);margin-bottom:0}
.fq{padding:1.1rem 0;border-bottom:1px solid var(--rule)}.fq:last-child{border-bottom:none}.fqq{font-family:var(--fs);font-size:.83rem;font-weight:700;color:var(--ink);margin-bottom:.4rem}.fqa{font-family:var(--fs);font-size:.78rem;color:var(--slate-mid);line-height:1.7}
.csh{background:var(--ink);padding:1.25rem 1.5rem;margin:1.5rem 0 0;border-left:4px solid var(--gold)}.csn{font-family:var(--fm);font-size:.55rem;letter-spacing:.15em;text-transform:uppercase;color:rgba(201,168,76,.65);margin-bottom:.4rem}.cst{font-family:var(--fd);font-size:1.5rem;font-weight:300;color:var(--cream);line-height:1.1}.css{font-family:var(--fs);font-size:.72rem;color:rgba(245,240,232,.45);margin-top:.4rem}
.trow{display:grid;grid-template-columns:130px 1fr;border-bottom:1px solid var(--rule)}.trow:last-child{border-bottom:none}.tw{padding:1.1rem 1.25rem;border-right:1px solid var(--rule);background:rgba(15,21,38,.03)}.twl{font-family:var(--fm);font-size:.56rem;letter-spacing:.1em;text-transform:uppercase;color:var(--gold);margin-bottom:.2rem}.td{padding:1.1rem 1.25rem}.td p{font-size:.77rem;margin-bottom:0}
.fg{display:grid;grid-template-columns:1fr 1fr;gap:0;border:1px solid var(--rule);margin:1.25rem 0}.fc{padding:1.4rem;border-right:1px solid var(--rule);border-bottom:1px solid var(--rule)}.fc:nth-child(2n){border-right:none}.fc:nth-child(3),.fc:nth-child(4){border-bottom:none}.fn{font-family:var(--fm);font-size:.52rem;letter-spacing:.12em;text-transform:uppercase;color:var(--gold);margin-bottom:.3rem}.ft{font-family:var(--fs);font-size:.8rem;font-weight:700;color:var(--ink);margin-bottom:.35rem}.fb{font-family:var(--fs);font-size:.73rem;color:var(--slate-mid);line-height:1.65}.ff{font-family:var(--fm);font-size:.57rem;color:var(--green);letter-spacing:.05em;margin-top:.45rem;border-left:2px solid var(--green);padding-left:.55rem}
.footer{background:var(--ink);color:rgba(245,240,232,.22);padding:1.4rem 3rem;display:flex;justify-content:space-between;font-family:var(--fm);font-size:.52rem;letter-spacing:.08em}.footer span:first-child{color:var(--gold);letter-spacing:.2em}
/* Blog */
.ab{max-width:740px;padding:2.5rem 3rem}.ab h2{font-family:var(--fd);font-size:1.65rem;font-weight:300;color:var(--ink);margin:2rem 0 .6rem;line-height:1.1;border-top:1px solid var(--rule);padding-top:1.5rem}.ab h3{font-family:var(--fs);font-size:.9rem;font-weight:700;color:var(--slate);margin:1.4rem 0 .4rem}.ab p{font-size:.83rem;color:var(--slate-mid);line-height:1.8;margin-bottom:.9rem}.ab ul{margin:.5rem 0 .9rem 1.2rem;color:var(--slate-mid)}.ab li{font-size:.83rem;line-height:1.7;margin-bottom:.3rem}.ab hr{border:none;border-top:1px solid var(--rule);margin:1.5rem 0}.ab strong{color:var(--slate)}.ab em{color:var(--slate-mid)}
.acta{background:var(--ink);padding:1.75rem 2rem;margin:2rem 0;display:flex;align-items:center;justify-content:space-between;gap:1rem}.acta p{color:rgba(245,240,232,.7);font-size:.8rem;margin:0;flex:1}.ctab{font-family:var(--fm);font-size:.6rem;font-weight:700;letter-spacing:.12em;text-transform:uppercase;padding:.55rem 1.3rem;background:var(--gold);color:var(--ink);white-space:nowrap;text-decoration:none}
